case "$(uname -s)" in
  Linux) ;;
  Darwin) die "macOS support not yet available. Track: README roadmap." ;;
  MINGW*|MSYS*|CYGWIN*) die "Detected Windows shell. Use install.ps1 in PowerShell:\n  powershell -ExecutionPolicy Bypass -Command \"iwr -useb https://raw.githubusercontent.com/USERNAME/dictate/main/install.ps1 | iex\"" ;;
  *) die "Unsupported OS: $(uname -s)" ;;
esac
